1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0], [1, 0],
6	  [-1, 1], [0, 1], [1, 1],
7	];
8	
9	const keyOf = (x: number, y: number): string => `${x},${y}`;
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const liveKeys = new Set(cells.map(([x, y]) => keyOf(x, y)));
13	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of cells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const nx = x + dx;
18	      const ny = y + dy;
19	      const key = keyOf(nx, ny);
20	      const existing = neighborCounts.get(key);
21	      if (existing) {
22	        existing.count += 1;
23	      } else {
24	        neighborCounts.set(key, { cell: [nx, ny], count: 1 });
25	      }
26	    }
27	  }
28	
29	  const nextCells: Cell[] = [];
30	  for (const [key, { cell, count }] of neighborCounts) {
31	    const survives = count === 2 && liveKeys.has(key);
32	    const reproduces = count === 3;
33	    if (survives || reproduces) {
34	      nextCells.push(cell);
35	    }
36	  }
37	  return nextCells;
38	}
39

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die from underpopulation — [(0,1), (1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with 4 neighbors dies from overpopulation — center of filled 3x3 dies", () => {
15	    // Full 3x3 block: center (1,1) has 8 live neighbors → dies
16	    const input: [number, number][] = [
17	      [0, 0], [1, 0], [2, 0],
18	      [0, 1], [1, 1], [2, 1],
19	      [0, 2], [1, 2], [2, 2],
20	    ];
21	    const result = nextGeneration(input);
22	    expect(result).not.toContainEqual([1, 1]);
23	  });
24	  it("dead cell with exactly 3 neighbors becomes alive (reproduction) — L-shape produces block", () => {
25	    // L-shape: (0,0),(1,0),(0,1) — dead cell (1,1) has 3 live neighbors → alive
26	    // All 3 live cells also have 2 live neighbors → survive
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it("live cell with 2 or 3 neighbors survives — center of row of 3 survives", () => {
31	    // Row of 3: (0,0),(1,0),(2,0). Middle (1,0) has 2 live neighbors → survives.
32	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
33	    expect(result).toContainEqual([1, 0]);
34	  });
35	  it.todo("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same");
36	  it.todo("blinker oscillates from vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
37	  it.todo("handles negative coordinates correctly");
38	});
